async function apiGet() {
    const r = await fetch("/api/private-data");
    if (!r.ok) throw new Error("Unauthorized");
    return r.json();
}
async function apiAppend(sheetName, row) {
    await fetch("/api/private-data", {
        method: "POST",
        headers: {
            "Content-Type": "application/json"
        },
        body: JSON.stringify({
            sheetName,
            row
        })
    });
}
