// ── Share Drop Tab ───────────────────────────────────────────────────────────
function estimateShipping(grams) {
    const oz = (grams + 30) / 28.35;
    if (oz <= 1) return 0.73;
    if (oz <= 2) return 1.00;
    if (oz <= 3) return 1.26;
    if (oz <= 4) return 1.53;
    if (oz <= 8) return 2.00;
    if (oz <= 12) return 2.50;
    if (oz <= 15.99) return 3.00;
    if (oz <= 32) return 7.50;
    if (oz <= 48) return 9.00;
    return 11.00;
}
